def main() -> None:
    doc = Document(str(SRC))
    changed = 0
    for idx, text in PARA_REPLACEMENTS.items():
        if idx < len(doc.paragraphs):
            doc.paragraphs[idx].text = text
            changed += 1
    doc.save(str(OUT))
    doc.save(str(OUT_EN))
    print(f"saved: {OUT}")
    print(f"saved: {OUT_EN}")
    print(f"changed paragraphs: {changed}")


if __name__ == "__main__":
    main()
